import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { ProductDetailResponse, PublicProduct, Category, Proveedor } from '../models';
import { StoreApiService } from '../services/store-api.service';
import { CartService } from '../services/cart.service';

@Component({
  selector: 'app-product-detail-page',
  standalone: true,
  imports: [CommonModule, RouterLink, FormsModule],
  template: `
    <!-- Breadcrumbs -->
    <nav class="flex items-center text-sm text-[#6b6d6b] mb-6">
      <a routerLink="/" class="hover:text-[#475841] transition-colors">Inicio</a>
      <span class="mx-2">›</span>
      <a *ngIf="product?.categoria" (click)="filterByCategory()" class="hover:text-[#475841] transition-colors">{{ product?.categoria?.nombre }}</a>
      <span *ngIf="product?.categoria" class="mx-2">›</span>
      <span class="text-[#3f403f] font-medium">{{ product?.nombre }}</span>
    </nav>

    <section *ngIf="loading" class="border border-[#ced0ce] bg-white p-8 text-center">
      <p class="text-[#6b6d6b]">Cargando detalle...</p>
    </section>

    <section *ngIf="error" class="border border-[#ced0ce] bg-white p-8 text-center">
      <p class="text-red-600">{{ error }}</p>
    </section>

    <ng-container *ngIf="product && !loading">
      <div class="grid grid-cols-1 lg:grid-cols-12 gap-8">
        <!-- Image Gallery Section -->
        <div class="lg:col-span-7 flex flex-col gap-4">
          <!-- Main Image -->
          <div class="w-full aspect-video md:aspect-[4/3] border border-[#ced0ce] bg-white rounded overflow-hidden flex items-center justify-center">
            <span class="text-9xl text-[#475841]">📦</span>
          </div>
          <!-- Thumbnails -->
          <div class="flex gap-4 overflow-x-auto">
            <button class="flex-shrink-0 w-24 h-24 border-2 border-[#475841] bg-white rounded overflow-hidden flex items-center justify-center">
              <span class="text-4xl text-[#475841]">📦</span>
            </button>
            <button class="flex-shrink-0 w-24 h-24 border border-[#ced0ce] hover:border-[#475841] bg-white rounded overflow-hidden flex items-center justify-center transition-colors">
              <span class="text-4xl text-[#475841]">📦</span>
            </button>
            <button class="flex-shrink-0 w-24 h-24 border border-[#ced0ce] hover:border-[#475841] bg-white rounded overflow-hidden flex items-center justify-center transition-colors">
              <span class="text-4xl text-[#475841]">📦</span>
            </button>
            <button class="flex-shrink-0 w-24 h-24 border border-[#ced0ce] hover:border-[#475841] bg-white rounded overflow-hidden flex items-center justify-center transition-colors">
              <span class="text-4xl text-[#475841]">📦</span>
            </button>
          </div>
        </div>

        <!-- Product Details Section -->
        <div class="lg:col-span-5 flex flex-col gap-6">
          <!-- Title & Price -->
          <div class="flex flex-col gap-2">
            <p class="text-sm text-[#6b6d6b]">{{ product.sku }}</p>
            <h1 class="text-3xl font-semibold tracking-tight text-[#3f403f]">{{ product.nombre }}</h1>
            <div class="mt-2 flex items-baseline gap-3">
              <span class="text-3xl font-semibold text-[#475841]">S/.{{ product.precio_descuento | number:'1.2-2' }}</span>
              <span *ngIf="product.descuento_tipo" class="text-lg text-[#6b6d6b] line-through">S/.{{ product.precio_venta }}</span>
              <span *ngIf="product.descuento_tipo === 'porcentaje'" class="bg-[#eaf1ed] text-[#475841] text-xs font-bold px-2 py-1">Ahorra {{ product.descuento_valor }}%</span>
            </div>
            <p *ngIf="product.cuotas_sin_interes" class="text-sm text-[#6b6d6b] mt-1">
              Hasta {{ product.cuotas }} cuotas sin interés de S/.{{ product.cuotas_mensual | number:'1.2-2' }}
            </p>
          </div>

          <!-- Delivery Status -->
          <div class="border border-[#ced0ce] bg-[#f8f9f8] rounded p-4 flex items-start gap-3">
            <span class="text-xl text-[#475841]">🚚</span>
            <div>
              <p class="text-lg font-semibold text-[#3f403f]">Llega entre el {{ freeShippingFrom }} y el {{ freeShippingTo }}</p>
              <p class="text-sm text-[#6b6d6b]">Vendido y entregado por CompraEnUna</p>
            </div>
          </div>

          <!-- Technical Specs (Bento Grid Style) -->
          <div class="grid grid-cols-2 gap-3">
            <div class="border border-[#ced0ce] bg-white rounded p-4 flex flex-col gap-1">
              <span class="text-xs font-bold uppercase tracking-wider text-[#6b6d6b]">Procesador</span>
              <span class="text-sm text-[#3f403f]">Intel Core i7</span>
            </div>
            <div class="border border-[#ced0ce] bg-white rounded p-4 flex flex-col gap-1">
              <span class="text-xs font-bold uppercase tracking-wider text-[#6b6d6b]">Memoria</span>
              <span class="text-sm text-[#3f403f]">16GB DDR5</span>
            </div>
            <div class="border border-[#ced0ce] bg-white rounded p-4 flex flex-col gap-1">
              <span class="text-xs font-bold uppercase tracking-wider text-[#6b6d6b]">Almacenamiento</span>
              <span class="text-sm text-[#3f403f]">512GB SSD</span>
            </div>
            <div class="border border-[#ced0ce] bg-white rounded p-4 flex flex-col gap-1">
              <span class="text-xs font-bold uppercase tracking-wider text-[#6b6d6b]">Pantalla</span>
              <span class="text-sm text-[#3f403f]">15.6" FHD</span>
            </div>
          </div>

          <!-- Quantity -->
          <div class="flex items-center gap-3">
            <label class="text-sm font-medium text-[#3f403f]">Cantidad:</label>
            <select [(ngModel)]="cantidad" (change)="onCantidadChange()" class="border border-[#ced0ce] bg-white px-4 py-2 text-sm rounded">
              <option [value]="1">1 unidad</option>
              <option [value]="2">2 unidades</option>
              <option [value]="3">3 unidades</option>
              <option [value]="4">4 unidades</option>
              <option [value]="5">5 unidades</option>
            </select>
          </div>

          <!-- Actions -->
          <div class="flex flex-col gap-3">
            <button (click)="addToCart()" class="bg-[#475841] text-white hover:bg-[#5b6d54] text-lg w-full h-12 rounded flex items-center justify-center transition-colors">
              Añadir al Carrito
            </button>
            <button class="bg-transparent border border-[#475841] text-[#475841] hover:bg-[#e6e8e6] text-sm w-full h-11 rounded flex items-center justify-center transition-colors gap-2">
              <span>♡</span>
              Guardar para después
            </button>
          </div>

          <!-- Payment Methods -->
          <div class="flex items-center gap-3 pt-4 border-t border-[#ced0ce]">
            <span class="text-sm text-[#6b6d6b]">Pago seguro con:</span>
            <div class="flex gap-2">
              <div class="w-10 h-6 border border-[#ced0ce] bg-white rounded flex items-center justify-center text-[10px] font-bold text-[#6b6d6b]">VISA</div>
              <div class="w-10 h-6 border border-[#ced0ce] bg-white rounded flex items-center justify-center text-[10px] font-bold text-[#6b6d6b]">MC</div>
            </div>
          </div>
        </div>
      </div>

      <!-- Detailed Description Section -->
      <div class="mt-10 border-t border-[#ced0ce] pt-10">
        <h2 class="text-2xl font-semibold tracking-tight text-[#3f403f] mb-4">Descripción del Producto</h2>
        <div class="prose max-w-none text-sm text-[#6b6d6b] flex flex-col gap-4">
          <p>{{ product.descripcion }}</p>
        </div>
      </div>

      <!-- Related Products -->
      <section *ngIf="relatedProducts.length > 0" class="mt-10">
        <h2 class="text-2xl font-semibold tracking-tight text-[#3f403f] mb-4">Productos relacionados</h2>
        <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <div *ngFor="let related of relatedProducts" class="border border-[#ced0ce] bg-white p-4">
            <h3 class="text-lg font-semibold text-[#3f403f]">{{ related.nombre }}</h3>
            <p class="text-[#475841] font-semibold">S/.{{ related.precio_descuento | number:'1.2-2' }}</p>
            <p *ngIf="related.envio_gratis" class="text-xs text-[#475841]">Envío gratis</p>
            <button routerLink="/producto/{{ related.id }}" class="mt-2 text-sm text-[#475841]">Ver producto</button>
          </div>
        </div>
      </section>
    </ng-container>
  `
})
export class ProductDetailPageComponent implements OnInit {
  loading = true;
  error = '';
  product: PublicProduct | null = null;
  relatedProducts: PublicProduct[] = [];
  brandProducts: PublicProduct[] = [];
  cantidad = 1;

  freeShippingFrom = '';
  freeShippingTo = '';

  private today = new Date();

  constructor(
    private readonly route: ActivatedRoute,
    private readonly router: Router,
    private readonly storeApi: StoreApiService,
    private readonly cart: CartService,
  ) {
    this.calculateShippingDates();
  }

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (id) {
      this.loadProduct(+id);
    } else {
      this.error = 'ID de producto no válido';
      this.loading = false;
    }
  }

  calculateShippingDates(): void {
    const from = new Date(this.today);
    const to = new Date(this.today);
    from.setDate(from.getDate() + 3);
    to.setDate(to.getDate() + 5);
    this.freeShippingFrom = from.toLocaleDateString('es-PE', { day: 'numeric', month: 'short' });
    this.freeShippingTo = to.toLocaleDateString('es-PE', { day: 'numeric', month: 'short' });
  }

  loadProduct(id: number): void {
    this.loading = true;
    this.storeApi.getProductById(id.toString()).subscribe({
      next: (res: ProductDetailResponse) => {
        this.product = res.product;
        this.relatedProducts = res.relatedProducts || [];
        this.brandProducts = [];
        this.loading = false;
      },
      error: () => {
        this.error = 'Error cargando producto';
        this.loading = false;
      },
    });
  }

  filterByBrand(): void {
    if (this.product?.proveedor) {
      this.router.navigate(['/'], { queryParams: { marca: this.product.proveedor.id } });
    }
  }

  filterByCategory(): void {
    if (this.product?.categoria) {
      this.router.navigate(['/'], { queryParams: { categoria: this.product.categoria.id } });
    }
  }

  onCantidadChange(): void {}

  addToCart(): void {
    if (this.product) {
      this.cart.addProduct(this.product);
      this.router.navigate(['/carrito']);
    }
  }

  buyNow(): void {
    this.addToCart();
    this.router.navigate(['/checkout']);
  }
}
